// UTILITY: DB Writer v1.0.0
// Reusable utility for writing records to PostgreSQL.
// Provides a safe, centralized write path with:
//   - Input validation
//   - Error wrapping
//   - Retry metadata
//
// INPUT:  { table: string, operation: 'insert'|'update'|'upsert', payload: object, conflict_on?: string }
// OUTPUT: { success: boolean, table: string, operation: string, row_id?: string, error?: string }
//
// PLACEHOLDER: Logs the intent but does not execute.
// In Phase 6, this will use n8n PostgreSQL node with parameterized queries.

const input = $input.first().json;
const { table, operation, payload, conflict_on } = input;

if (!table)     throw new Error('[util_db_writer] Missing required field: table');
if (!operation) throw new Error('[util_db_writer] Missing required field: operation');
if (!payload)   throw new Error('[util_db_writer] Missing required field: payload');

const validOps = ['insert', 'update', 'upsert'];
if (!validOps.includes(operation)) throw new Error(`[util_db_writer] Invalid operation: ${operation}. Must be: ${validOps.join(', ')}`);

console.log(`[util_db_writer] ${operation.toUpperCase()} → ${table} (placeholder, not persisted)`);

return [{
  json: {
    success:   false,
    table,
    operation,
    row_id:    null,
    persisted: false,
    note:      'PLACEHOLDER — Will execute real PostgreSQL operation in Phase 6'
  }
}];
